const express = require('express');
const jwt = require('jsonwebtoken');
const axios = require('axios');

const app = express();

app.use(express.urlencoded({ extended: true }));
app.use(express.json());

// Set up the OpenID Connect client
const clientId = 'your_client_id';
const clientSecret = 'your_client_secret';
const oidcIssuer = 'https://your_oidc_issuer';
const redirectUri = 'http://localhost:3000/callback';

// Set up the user sessions
const sessionStore = new express.session();

app.get('/login', (req, res) => {
  const authorizationUrl = `${oidcIssuer}/authorize?response_type=code&client_id=${clientId}&redirect_uri=${redirectUri}`;
  res.redirect(authorizationUrl);
});

app.get('/callback', (req, res) => {
  const code = req.query.code;
  axios.post(`${oidcIssuer}/token`, {
    grant_type: 'authorization_code',
    client_id: clientId,
    client_secret: clientSecret,
    redirect_uri: redirectUri,
    code: code,
  })
  .then((response) => {
    const accessToken = response.data.access_token;
    axios.get(`${oidcIssuer}/userinfo`, {
      headers: {
        Authorization: `Bearer ${accessToken}`,
      },
    })
    .then((response) => {
      const idToken = response.data.id_token;
      jwt.decode(idToken, (err, decoded) => {
        if (err) {
          console.error(err);
          return res.sendStatus(500);
        }
        const userInfo = decoded;
        sessionStore.set('user', userInfo);
        res.redirect('/');
      });
    })
    .catch((error) => {
      console.error(error);
      return res.sendStatus(500);
    });
  })
  .catch((error) => {
    console.error(error);
    return res.sendStatus(500);
  });
});

app.get('/', (req, res) => {
  const userInfo = sessionStore.get('user');
  if (!userInfo) {
    res.redirect('/login');
  } else {
    res.json({
      sub: userInfo.sub,
      email: userInfo.email,
      name: userInfo.name,
    });
  }
});

app.listen(3000, () => {
  console.log('Server started on port 3000');
});